let toastHandler = null

export const setToastHandler = (handler) => {
  toastHandler = typeof handler === 'function' ? handler : null
}

export const pushToast = ({ title, message, type = 'info', duration = 4000 }) => {
  if (!toastHandler) return
  toastHandler({ title, message, type, duration })
}
